getBuildOptions.code:
// Apply bulk discount based on structure count
const totalStructures = state.structures?.length || 0;
const discountTier = Math.floor(totalStructures / 5); // 5 structures = 1 tier
discountMultiplier = Math.max(0.5, 1 - (discountTier * 0.1)); // Max 50% discount

// Return modified build options with discount applied
// This would modify the actual build options in a real implementation
return {
  ...state,
  buildCostModifier: discountMultiplier,
  discountTier: discountTier
};

placeStructure.code:
// Apply discount to structure placement
const discountMultiplier = state.buildCostModifier || 1;
if (discountMultiplier < 1) {
  // Calculate discounted cost
  const originalCost = action.price || { iron: 5 };
  const discountedCost = {
    iron: Math.ceil((originalCost.iron || 0) * discountMultiplier)
  };

  return kernel.mutateState({
    ...state,
    lastAppliedDiscount: discountMultiplier,
    originalCost,
    discountedCost
  });
}
return state;
